%[text] # 例8.8（超解像）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example08_08"; % mfilename

imgname = "msipimg08";
imgfmt = "tiff";

rng(0)
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
I = imresize(im2double(rgb2gray(imread(imgfile,imgfmt))),[96 96],'bilinear');
%%
%[text] ## 幾何処理前の画像表示
figure(1) %[output:397c5358]
imshow(I)  %[output:397c5358]
title('原画像')  %[output:397c5358]
%%
%[text] ## 観測画像
hsigma  = 2;                    % ガウスカーネル分散
hsize   = 2*ceil(2*hsigma)+1;   % ガウスカーネルサイズ
nvar    = (10/255)^2;            % 加法性白色ガウスノイズ分散
psf = fspecial('gaussian',hsize,hsigma);   

% 測定過程
measureproc = @(x) downsample2(imfilter(x,psf,'conv','circular'),[2 2]); % H
measureadjp = @(x) imfilter(upsample2(x,[2 2]),psf,'corr','circular'); % H.'
U = measureproc(I);

% 測定過程の整合性チェック
%assert(norm(U - imresize(I,0.5,'box'),'fro')<1e-6)

% AWGN
V = imnoise(measureproc(I),'gaussian',0,nvar);

% 随伴関係 <Sx,v> = <x,S.'v> の確認
W = measureadjp(V);
assert(abs(dot(U(:),V(:))-dot(I(:),W(:)))<1e-6)

%%
%[text] ### 観測画像の表示
figure(2) %[output:46717760]
imshow(V) %[output:46717760]
title('観測画像')  %[output:46717760]

%%
%[text] ### 双三次補間
Yb = imresize(V,2,'bicubic');
figure(3) %[output:92b6deb2]
imshow(Yb) %[output:92b6deb2]
title("双三次補間 PSNR: "+num2str(psnr(I,Yb))+" dB")  %[output:92b6deb2]
%[text] ## 
%%
%[text] ### 復元前処理
vpst = rand(size(V),'like',V);
lpre = 1.0;
err_ = Inf;
while ( err_ >  1e-5 ) % べき乗法
    % vpst = (P.'*P)*vupre
    vpre = vpst/norm(vpst(:));
    u    = measureproc(vpre); % P
    vpst = measureadjp(u);    % P.'
    n    = (vpst(:).'*vpst(:));
    d    = (vpst(:).'*vpre(:));
    lpst = n/d;
    err_ = norm(lpst-lpre);
    lpre = lpst;
end
frameBound = 1; % フレーム境界
L = frameBound*lpst; % 勾配のリプシッツ定数
fprintf('L = %g\n',L); %[output:8bd4f39b]
%%
%[text] ### 制約付き1-ノルム正則化超解像
import msip.udhaarwtdec2
import msip.udhaarwtrec2

lambda = 6e-4;
nLevels = 5;
%
eta1 = 1/L;
eta2 = (1/eta1)-L/2;
assert(eta1 > 0)
assert(eta2 > 0)
assert((1/eta1)-eta2 >= L/2)
%
[coefs,scales] = udhaarwtdec2(I,nLevels);
R = udhaarwtrec2(coefs,scales);
assert(norm(I-R,"fro")^2/numel(I)<1e-18,'Perfect reconstruction is violated.')

% 合成辞書と転置辞書の定義 
adjdic = @(x) udhaarwtdec2(x,nLevels); % D
syndic = @(x) udhaarwtrec2(x,scales);  % D.'

% モニタリング
nIters = 20;
X = zeros(size(I),'like',I);
figure(4)
him = imshow(zeros(size(I))); %[output:56d45bd1]
htt = title("制約付き1-ノルム正則化 PSNR: "+num2str(psnr(I,X))+" dB") ; %[output:56d45bd1]

S = zeros(size(coefs),'like',coefs);
for iter = 1:nIters %[output:group:28a5e2c5]
    g = adjdic( measureadjp( measureproc( syndic(S) ) - V ) ); 
    Spre = S;
    S = softthresh( Spre - eta1*(g + adjdic(X)), lambda*eta1);
    U = X + eta2*syndic(2*S-Spre);
    X = U - eta2*min(max(U/eta2,0),1);
    %
    if mod(iter,2)==0 || iter == nIters
        Yc = syndic(S);
        him.CData = Yc; %[output:56d45bd1]
        htt.String = "制約付き1-ノルム正則化 PSNR: "+num2str(psnr(I,Yc))+" dB" +"("+num2str(iter)+")";
        drawnow
    end
end %[output:group:28a5e2c5]
Yc = syndic(S);
%%
%[text] ### TV正則化超解像
%[text] 勾配フィルタ
gv = [0  1 0;
      0 -1 0;
      0  0 0];
gh = rot90(gv);
gradproc = @(x) cat(3,imfilter(x,gv,'conv','circ'),imfilter(x,gh,'conv','circ'));
gradadjp = @(x) imfilter(x(:,:,1),gv,'corr','circ') + imfilter(x(:,:,2),gh,'corr','circ');
% 随伴関係 <Sx,v> = <x,S.'v> の確認
J = gradproc(I);
K = rand(size(J),'like',J);
% 随伴関係 <Sx,v> = <x,S.'v> の確認
W = gradadjp(K);
assert(abs(dot(J(:),K(:))-dot(I(:),W(:)))<1e-6)
%[text] パラメータの設定
lambda = 5e-4;
%
nPoints = 2.^nextpow2(size(I));
beta = max(abs(fftn(psf,nPoints)).^2,[],'all')/lambda; % (σmax(H))^2/λ
tau  = max(abs(fftn(gv,nPoints)).^2,[],'all');  % (σmax(G))^2
eta1 = 1/beta;
eta2 = (1/eta1-beta/2)/tau;
assert(eta1 > 0)
assert(eta2 > 0)
assert((1/eta1)-eta2*tau >= beta/2)
%
nIters = 20;
% モニタリング
Xpre = zeros(size(I),'like',I);
figure(5) %[output:5151f95a]
him = imshow(zeros(size(I))); %[output:5151f95a]
htt = title("制約付きTV正則化 PSNR: "+num2str(psnr(I,Xpre))+" dB") ; %[output:5151f95a]
Y = gradproc(Xpre);
for iter = 1:nIters %[output:group:9637f76c]
    % 主問題
    g = measureadjp( measureproc( Xpre ) - V ); 
    X = min(max(Xpre - eta1*( g/lambda + gradadjp(Y)),0),1);
    % 双対問題
    u = Y + eta2*gradproc(2*X - Xpre);
    Y = u - magshrink(u);
    %
    if mod(iter,2)==0 || iter == nIters
        him.CData = X; %[output:5151f95a]
        htt.String = "制約付きTV正則化 PSNR: "+num2str(psnr(I,X))+" dB" +"("+num2str(iter)+")";
        drawnow
    end
    % 更新
    Xpre = X;
end %[output:group:9637f76c]
%%
%[text] ## 結果出力
imwrite(V, fullfile(resfolder,"fig08-10a.png"))
imwrite(Yb,fullfile(resfolder,"fig08-10b.png"))
imwrite(Yc,fullfile(resfolder,"fig08-10c.png"))
imwrite(X,fullfile(resfolder, "fig08-10d.png"))
%%
%[text] ソフト閾値処理
function y = softthresh(x,lambda)
    y = x + abs(x-lambda)/2 - abs(x+lambda)/2;
end

function y = downsample2(x,M)
    z = downsample(x,M(1)).';
    y = downsample(z,M(2)).';
end

function y = upsample2(x,M)
    z = upsample(x,M(1)).';
    y = upsample(z,M(2)).';
end
%[text] 振幅ソフト閾値処理
function y = magshrink(x)
    Gv = x(:,:,1);
    Gh = x(:,:,2);
    Gmag = imgradient(Gh,Gv);
    map = max(1 - 1./Gmag, 0);
    y = x.*map;
end
